import{j as e,b as t,c as a,aa as s}from"./chunks/framework.Bxf40uRC.js";const u=JSON.parse('{"title":"Rpc","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/RPC.md","filePath":"计算机网络/RPC.md","lastUpdated":null}'),r={name:"计算机网络/RPC.md"},l=s('<h1 id="rpc" tabindex="-1">Rpc <a class="header-anchor" href="#rpc" aria-label="Permalink to &quot;Rpc&quot;">​</a></h1><h3 id="_1、结构图" tabindex="-1">1、结构图 <a class="header-anchor" href="#_1、结构图" aria-label="Permalink to &quot;1、结构图&quot;">​</a></h3><p><img src="https://s2.loli.net/2023/12/16/yTcsKSxhfIOq39o.png" alt="image-20230810111051116"></p><ul><li>客户端以本地调用的方式调用服务</li><li>client stub接收到调用后负责将方法，参数组装成能够进行网络传输的消息体，(序列化操作)</li><li>Client stub找到服务端地址，将消息发送到服务端</li><li>server stub接收到消息后进行解码，根据解码结果调用本地服务</li><li>本地服务执行完毕后返回给server stub，server stub将结果打包成消息发送给客户端</li><li>client stub接收到消息后进行解码然后得到结果(反序列化操作)</li></ul><p>总结来说一共包含三个部分<em><strong>call ID映射</strong></em>，<em><strong>序列化和反序列化</strong></em>，<em><strong>网络传输</strong></em></p>',5),i=[l];function o(n,c,_,p,d,m){return t(),a("div",null,i)}const b=e(r,[["render",o]]);export{u as __pageData,b as default};
